const items = $input.all().map(item => item.json);

const lines = ['🚨 BAO CAO TASK QUA HAN'];

if (!items.length) {
  lines.push('');
  lines.push('✅ Khong co task qua han.');
} else {
  items.forEach((task, index) => {
    lines.push('');
    lines.push(`*TASK ${index + 1}*`);
    lines.push(`🆔 *Ma task:* ${task.taskId || '-'}`);
    lines.push(`📝 *Ten task:* ${task.taskName || '-'}`);
    lines.push(`👤 Nguoi duoc giao: ${task.assigneeEmail || '-'}`);
    lines.push(`🔥 Uu tien: ${task.priority || '-'}`);
    lines.push(`📅 Deadline: ${task.deadlineDisplay || task.deadline || '-'}`);
  });
}

return [{
  json: {
    report: lines.join('\n'),
    count: items.length,
    tasks: items
  }
}];

const parseDate = (value) => {
  if (!value) return null;

  if (Array.isArray(value)) {
    const [year, month = 1, day = 1, hour = 0, minute = 0, second = 0, nano = 0] = value;
    const millis = Math.floor(Number(nano) / 1000000);
    const date = new Date(year, month - 1, day, hour, minute, second, millis);
    return Number.isNaN(date.getTime()) ? null : date;
  }

  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
};

const formatDate = (value) => {
  const date = parseDate(value);
  if (!date) return null;

  const pad = (input) => String(input).padStart(2, '0');
  return `${pad(date.getDate())}/${pad(date.getMonth() + 1)}/${date.getFullYear()} ${pad(date.getHours())}:${pad(date.getMinutes())}`;
};

const now = new Date();

return $input.all().map((entry) => {
  const item = entry.json ?? {};
  const deadline = parseDate(item.deadline);
  const daysLeft = deadline ? Math.ceil((deadline.getTime() - now.getTime()) / 86400000) : null;

  return {
    json: {
      ...item,
      deadline: deadline?.toISOString() ?? item.deadline ?? null,
      deadlineDisplay: item.deadlineDisplay ?? formatDate(item.deadline) ?? 'Chua co deadline',
      daysLeft
    }
  };
});

const parseDate = (value) => {
  if (!value) return null;

  if (Array.isArray(value)) {
    const [year, month = 1, day = 1, hour = 0, minute = 0, second = 0, nano = 0] = value;
    const millis = Math.floor(Number(nano) / 1000000);
    const date = new Date(year, month - 1, day, hour, minute, second, millis);
    return Number.isNaN(date.getTime()) ? null : date;
  }

  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
};

const formatDate = (value) => {
  const date = parseDate(value);
  if (!date) return null;

  const pad = (input) => String(input).padStart(2, '0');
  return `${pad(date.getDate())}/${pad(date.getMonth() + 1)}/${date.getFullYear()} ${pad(date.getHours())}:${pad(date.getMinutes())}`;
};

const deadline = parseDate($json.deadline);
const completedAt = parseDate($json.completedAt) ?? new Date();
const isEarly = deadline ? completedAt.getTime() <= deadline.getTime() : false;

return [{
  json: {
    ...$json,
    deadline: deadline?.toISOString() ?? $json.deadline ?? null,
    deadlineDisplay: $json.deadlineDisplay ?? formatDate($json.deadline) ?? 'Chua co deadline',
    completedAt: completedAt.toISOString(),
    completedAtDisplay: formatDate(completedAt),
    isEarly
  }
}];

const body = $json.body ?? $json;

const parseDate = (value) => {
  if (!value) return null;

  if (Array.isArray(value)) {
    const [year, month = 1, day = 1, hour = 0, minute = 0, second = 0, nano = 0] = value;
    const millis = Math.floor(Number(nano) / 1000000);
    const date = new Date(year, month - 1, day, hour, minute, second, millis);
    return Number.isNaN(date.getTime()) ? null : date;
  }

  if (typeof value === 'object') {
    const date = new Date(value);
    return Number.isNaN(date.getTime()) ? null : date;
  }

  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
};

const formatDate = (value) => {
  const date = parseDate(value);
  if (!date) return null;

  const pad = (input) => String(input).padStart(2, '0');
  return `${pad(date.getDate())}/${pad(date.getMonth() + 1)}/${date.getFullYear()} ${pad(date.getHours())}:${pad(date.getMinutes())}`;
};

const deadlineRaw = body.deadline ?? body.dueDate ?? body.endDate;
const description = body.taskDescription ?? body.adminNote ?? body.sourceInput ?? body.description ?? null;
const note = body.adminNote ?? body.sourceInput ?? body.taskDescription ?? null;
const deadlineDate = parseDate(deadlineRaw);
const completedDate = parseDate(body.completedAt);
const createdDate = parseDate(body.createdAt);

return [{
  json: {
    taskId: body.taskId,
    taskName: body.taskName,
    taskDescription: description,
    adminNote: body.adminNote ?? null,
    sourceInput: body.sourceInput ?? null,
    assigneeEmail: body.assigneeEmail,
    managerEmail: body.managerEmail,
    ownerName: body.ownerName,
    priority: body.priority,
    status: body.status,
    eventType: body.eventType ?? null,
    eventMessage: body.eventMessage ?? null,
    deadline: deadlineDate?.toISOString() ?? deadlineRaw ?? null,
    deadlineDisplay: formatDate(deadlineRaw) ?? (typeof deadlineRaw === 'string' ? deadlineRaw : null) ?? 'Chưa có deadline',
    createdAt: createdDate?.toISOString() ?? body.createdAt ?? null,
    createdAtDisplay: formatDate(body.createdAt),
    completedAt: completedDate?.toISOString() ?? null,
    completedAtDisplay: formatDate(body.completedAt),
    reminderCount: body.reminderCount ?? 0,
    note,
    receivedAt: new Date().toISOString()
  }
}];

return $input.all().map((entry) => {
  const item = entry.json ?? {};
  return {
    json: {
      ...item,
      taskId: item.taskId ?? 'UNKNOWN',
      taskName: item.taskName ?? 'Untitled task',
      assigneeEmail: item.assigneeEmail ?? null,
      priority: item.priority ?? 'MEDIUM',
      status: item.status ?? 'PENDING',
      deadline: item.deadline ?? null,
      daysLeft: item.daysLeft ?? null,
      reminderCount: item.reminderCount ?? 0,
    }
  };
});

return {
  json: {
    ...$json,
    opsMessage: [
      '⏰ THONG BAO NHAC VIEC',
      `📝 Task: ${$json.taskName || '-'}`,
      `🆔 Ma task: ${$json.taskId || '-'}`,
      `👤 Nguoi duoc giao: ${$json.assigneeEmail || '-'}`,
      `📉 Con lai: ${$json.daysLeft ?? 'NA'} ngay`,
      `📅 Deadline: ${$json.deadlineDisplay || $json.deadline || '-'}`
    ].join('\n')
  }
};

return {
  json: {
    ...$json,
    overdueDays: $json.overdueDays ?? null,
    escalatedAt: new Date().toISOString()
  }
};

return [{
  json: {
    ...$json,
    opsMessage: [
      '📊 BAO CAO HE THONG CUOI NGAY',
      '',
      `📂 Tong task dang mo: ${$json.totalOpen ?? '-'}`,
      `🚨 Task qua han: ${$json.overdueCount ?? '-'}`,
      `🔥 Task uu tien cao: ${$json.highPriorityCount ?? '-'}`,
      `⚙️ Task dang xu ly: ${$json.inProgressCount ?? '-'}`,
      `✅ Task da hoan thanh: ${$json.doneCount ?? '-'}`,
      `🕒 Thoi diem chup: ${new Date().toLocaleString('vi-VN')}`
    ].join('\n')
  }
}];

const items = $input.all().map((entry) => entry.json ?? {});
const normalize = (value) => String(value || '').trim().toUpperCase().replace(/[\s-]+/g, '_');

const totalOpen = items.length;
const highPriorityCount = items.filter((item) => normalize(item.priority) === 'HIGH').length;
const inProgressCount = items.filter((item) => normalize(item.status) === 'IN_PROGRESS').length;
const doneCount = items.filter((item) => normalize(item.status) === 'DONE').length;
const overdueCount = items.filter((item) => normalize(item.status) === 'OVERDUE').length;

const assigneeCounts = {};
for (const item of items) {
  const assignee = item.assigneeEmail || item.ownerName || 'Chua ro';
  assigneeCounts[assignee] = (assigneeCounts[assignee] || 0) + 1;
}

const topAssignee = Object.entries(assigneeCounts).sort((a, b) => b[1] - a[1])[0] || null;
const topAssigneeLabel = topAssignee ? `${topAssignee[0]} (${topAssignee[1]})` : '-';

const focusTasks = [...items]
  .filter((item) => ['OVERDUE', 'IN_PROGRESS', 'PENDING'].includes(normalize(item.status)))
  .sort((a, b) => {
    const priorityRank = { HIGH: 0, MEDIUM: 1, LOW: 2 };
    const aPriority = priorityRank[normalize(a.priority)] ?? 9;
    const bPriority = priorityRank[normalize(b.priority)] ?? 9;
    if (aPriority !== bPriority) return aPriority - bPriority;
    const aDeadline = Date.parse(a.deadline || '') || Number.MAX_SAFE_INTEGER;
    const bDeadline = Date.parse(b.deadline || '') || Number.MAX_SAFE_INTEGER;
    return aDeadline - bDeadline;
  })
  .slice(0, 3)
  .map((item) => ({
    taskId: item.taskId || null,
    taskName: item.taskName || null,
    assigneeEmail: item.assigneeEmail || null,
    status: item.status || null,
    deadline: item.deadline || null,
    deadlineDisplay: item.deadlineDisplay || item.deadline || null
  }));

return [{
  json: {
    items,
    totalOpen,
    highPriorityCount,
    inProgressCount,
    doneCount,
    overdueCount,
    topAssigneeLabel,
    focusTasks,
    snapshotAt: items[0]?.snapshotAt || new Date().toISOString()
  }
}];

const snapshotAt = new Date().toISOString();
return $input.all().map((entry) => ({
  json: {
    ...(entry.json ?? {}),
    snapshotAt
  }
}));

const snapshotAt = $json.snapshotAt || new Date().toISOString();
const focusTasks = Array.isArray($json.focusTasks) ? $json.focusTasks : [];

const formatStatus = (status) => {
  const value = String(status || '').toUpperCase();
  if (value === 'IN_PROGRESS') return 'Dang xu ly';
  if (value === 'OVERDUE') return 'Qua han';
  if (value === 'DONE') return 'Da hoan thanh';
  if (value === 'PENDING') return 'Cho xu ly';
  return status || '-';
};

const lines = [
  '📊 BAO CAO HE THONG CUOI NGAY',
  '',
  `📂 Tong task dang mo: ${$json.totalOpen ?? 0}`,
  `🚨 Task qua han: ${$json.overdueCount ?? 0}`,
  `⚙️ Dang xu ly: ${$json.inProgressCount ?? 0}`,
  `✅ Da hoan thanh: ${$json.doneCount ?? 0}`,
  `🔥 Uu tien cao: ${$json.highPriorityCount ?? 0}`,
  `👤 Nhieu task nhat: ${$json.topAssigneeLabel || '-'}`,
  `🕒 Thoi diem chup: ${snapshotAt}`
];

if (focusTasks.length) {
  lines.push('');
  lines.push('🎯 TASK CAN CHU Y:');
  focusTasks.forEach((task, index) => {
    lines.push(
      `${index + 1}. ${task.taskName || '-'} | ${task.assigneeEmail || '-'} | ${formatStatus(task.status)} | ${task.deadlineDisplay || task.deadline || '-'}`
    );
  });
}

return [{
  json: {
    ...$json,
    fileContent: lines.join('\n')
  }
}];
